html:
{% set co = get_company_info(doc.company) %}
{% set co_addr = get_company_address(doc.company) %}
{% set company_logo = frappe.db.get_value('Company', doc.company, 'company_logo') or '/files/logo.png' %}
{% set items = doc.items %}
{% set total_items = items | length %}

<style>
@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&display=swap');

@page {
  size: A4;
  margin: 15mm 10mm 22mm 10mm;
}

* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  font-family: 'Inter', sans-serif;
  color: #1f2937;
  background: #f3f4f6;
  padding: 20px;
}

/* Outer page container (fits A4 viewport) */
.ol-page {
  position: relative;
  width: 100%;
  max-width: 190mm;
  height: 250mm;
  border: none;
  padding: 0;
  margin: 0 auto 30px auto;
  background: white;
  page-break-after: always;
  box-sizing: border-box;
}

/* Inner border container offset from physical page top/bottom edges */
.ol-page-inner {
  position: relative;
  width: 100%;
  height: 228mm;
  border: 1.5px solid #9ca3af;
  margin-top: 10mm;
  padding: 20px 15px 15px 15px;
  box-sizing: border-box;
  background: white;
}

@media print {
  body {
    padding: 0;
    background: white;
  }
  .ol-page {
    width: 100% !important;
    max-width: 100% !important;
    margin: 0;
    box-shadow: none;
    border: none !important;
    height: 250mm !important;
  }
  .ol-page-inner {
    width: 100% !important;
    height: 228mm !important;
    border: 1.5px solid #9ca3af !important;
    margin-top: 10mm !important;
  }
}

.ol-page.ol-cover-page {
  border: none;
  box-shadow: none;
  padding: 0;
}

@media print {
  .ol-page.ol-cover-page {
    border: none !important;
  }
}

/* --- Logo Overlapping Border (Safely nested inside .ol-page-inner) --- */
.ol-logo-container {
  position: absolute;
  top: -22px;
  left: 15px;
  background: white;
  padding: 0 12px;
  z-index: 10;
  display: flex;
  align-items: center;
}

.ol-logo-container img {
  max-height: 38px;
  object-fit: contain;
}

.ol-logo-text {
  font-size: 16px;
  font-weight: 800;
  color: #111827;
  letter-spacing: -0.5px;
}

/* --- Contact Info Overlapping Border (Safely nested inside .ol-page-inner) --- */
.ol-header-right {
  position: absolute;
  top: -9px;
  right: 15px;
  background: white;
  padding: 0 12px;
  z-index: 10;
  font-size: 9.5px;
  color: #6b7280;
}

.ol-header-right a {
  color: #4b5563;
  text-decoration: none;
}

/* --- Document Title --- */
.ol-title-container {
  margin-top: 15px;
  margin-bottom: 20px;
  display: flex;
  justify-content: space-between;
  align-items: baseline;
}

.ol-title-text {
  font-size: 18px;
  font-weight: 800;
  color: #111827;
  letter-spacing: 0.5px;
}

.ol-title-date {
  font-size: 11px;
  font-weight: 700;
  color: #374151;
}

/* --- Client Details Grid --- */
.ol-info-table {
  width: 100%;
  border-collapse: collapse;
  margin-bottom: 25px;
}

.ol-info-title {
  font-size: 9px;
  font-weight: 700;
  color: #9ca3af;
  text-transform: uppercase;
  margin-bottom: 5px;
}

.ol-info-client-name {
  font-size: 13px;
  font-weight: 700;
  color: #111827;
  margin-bottom: 4px;
}

.ol-info-client-details {
  font-size: 10px;
  color: #4b5563;
  line-height: 1.5;
}

.ol-meta-table {
  width: 100%;
  border-collapse: collapse;
}

.ol-meta-table td {
  padding: 3px 0;
  font-size: 10px;
  color: #4b5563;
}

.ol-meta-label {
  font-weight: 600;
  width: 90px;
  color: #374151;
}

/* --- Items Table --- */
table.ol-items {
  width: 100%;
  border-collapse: collapse;
  font-size: 10px;
  margin-bottom: 15px;
}

table.ol-items thead tr {
  background-color: #f3f4f6;
  border-top: 1px solid #d1d5db;
  border-bottom: 1px solid #d1d5db;
}

table.ol-items th {
  padding: 6px 8px;
  font-weight: 700;
  color: #374151;
  text-transform: uppercase;
  font-size: 9px;
  letter-spacing: 0.5px;
}

table.ol-items td {
  padding: 8px 8px;
  border-bottom: 1px solid #e5e7eb;
  vertical-align: middle;
}

.ol-item-code {
  font-weight: 600;
  color: #4b5563;
}

.ol-item-img {
  max-width: 45px;
  max-height: 45px;
  object-fit: contain;
  border: 1px solid #e5e7eb;
  border-radius: 3px;
}

.ol-item-img-placeholder {
  width: 45px;
  height: 45px;
  background-color: #f9fafb;
  border: 1px dashed #d1d5db;
  border-radius: 3px;
  display: flex;
  align-items: center;
  justify-content: center;
  color: #9ca3af;
  font-size: 14px;
}

.ol-item-name {
  font-weight: 700;
  color: #111827;
  margin-bottom: 2px;
}

.ol-item-desc {
  font-size: 8.5px;
  color: #6b7280;
  line-height: 1.4;
}

/* --- Totals --- */
.ol-totals-container {
  display: flex;
  justify-content: flex-end;
  margin-bottom: 15px;
}

.ol-totals-table {
  width: 250px;
  border-collapse: collapse;
}

.ol-totals-table td {
  padding: 4px 8px;
  font-size: 10px;
  color: #4b5563;
}

.ol-totals-value {
  text-align: right;
  font-weight: 600;
  color: #111827;
}

.ol-totals-grand-row td {
  padding: 8px 8px;
  font-size: 12px;
  font-weight: 800;
  color: #111827;
  border-top: 1px solid #9ca3af;
  border-bottom: 1px solid #9ca3af;
  background-color: #f9fafb;
}

/* --- Payment Terms Line --- */
.ol-payment-terms {
  text-align: center;
  font-size: 10.5px;
  font-weight: 700;
  color: #111827;
  margin-top: 5px;
  margin-bottom: 15px;
}

/* --- Terms & Conditions --- */
.ol-terms-container {
  margin-top: 10px;
  margin-bottom: 15px;
}

.ol-terms-title {
  font-size: 10px;
  font-weight: 700;
  color: #374151;
  text-transform: uppercase;
  margin-bottom: 6px;
}

.ol-terms-text {
  font-size: 9px;
  color: #6b7280;
  line-height: 1.5;
}

/* --- Signatures --- */
.ol-sig-table {
  width: 100%;
  border-collapse: collapse;
  margin-top: 20px;
}

.ol-sig-title {
  font-size: 10px;
  font-weight: 700;
  color: #374151;
  text-transform: uppercase;
  border-bottom: 1px solid #d1d5db;
  padding-bottom: 4px;
  margin-bottom: 8px;
}

.ol-sig-placeholder {
  height: 85px;
  display: flex;
  align-items: center;
}

.ol-sig-details {
  font-size: 9px;
  color: #6b7280;
  line-height: 1.5;
}

/* --- Page Footer (Positioned safely below the inner border container) --- */
.ol-footer {
  position: absolute;
  bottom: 8px;
  left: 0;
  width: 100%;
  text-align: center;
  line-height: 1.4;
  color: #1f2937;
  font-size: 9.5px;
}

.ol-footer-company {
  font-weight: 800;
  font-size: 11px;
  color: #111827;
  letter-spacing: 0.5px;
  margin-bottom: 1px;
}

.ol-footer-address, .ol-footer-meta {
  font-weight: 500;
}

.ol-footer-meta a {
  color: #1f2937;
  text-decoration: underline;
}

/* --- Cover Page Styling --- */
.ol-cover-container {
  width: 100%;
  height: 100%;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  padding: 25px;
  background: white;
  border: 1px solid #d1d5db;
}

.ol-cover-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.ol-cover-logo img {
  max-height: 44px;
}

.ol-cover-body-table {
  width: 100%;
  border-collapse: collapse;
  margin: 20px 0;
}

.ol-cover-image-container {
  width: 100mm;
  height: 140mm;
  overflow: hidden;
  border-radius: 6px;
  box-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.1);
}

.ol-cover-img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.ol-cover-details {
  display: flex;
  flex-direction: column;
  justify-content: center;
}

.ol-cover-brand {
  font-size: 22px;
  font-weight: 800;
  color: #111827;
  margin-bottom: 5px;
}

.ol-cover-subtitle {
  font-size: 10px;
  font-weight: 600;
  color: #6b7280;
  text-transform: uppercase;
  letter-spacing: 1px;
  margin-bottom: 25px;
}

.ol-cover-title {
  font-size: 30px;
  font-weight: 800;
  color: #111827;
  line-height: 1.2;
  margin-bottom: 20px;
}

.ol-cover-divider {
  width: 60px;
  height: 4px;
  background-color: #111827;
  margin-bottom: 30px;
}

.ol-cover-meta-item {
  margin-bottom: 12px;
}

.ol-cover-meta-label {
  font-size: 10px;
  font-weight: 700;
  color: #9ca3af;
  text-transform: uppercase;
  margin-bottom: 4px;
}

.ol-cover-meta-value {
  font-size: 13px;
  font-weight: 700;
  color: #1f2937;
}

.ol-cover-footer {
  border-top: 1px solid #e5e7eb;
  padding-top: 20px;
  display: flex;
  justify-content: space-between;
  align-items: center;
  font-size: 10px;
  color: #6b7280;
}

.ol-cover-partners {
  font-weight: 700;
  color: #374151;
}

.tr { text-align: right; }
.tc { text-align: center; }
.tl { text-align: left; }
</style>

{# ==================== MACROS ==================== #}
{% macro render_header() %}
<div class="ol-logo-container">
  {%- if company_logo -%}
    <img src="{{ company_logo }}" alt="{{ doc.company }}">
  {%- else -%}
    <div class="ol-logo-text">{{ doc.company }}</div>
  {%- endif -%}
</div>
<div class="ol-header-right">
  {%- if co.email %}<a href="mailto:{{ co.email }}">{{ co.email }}</a>{% endif %}
  {%- if co.website %} | <a href="{{ co.website }}" target="_blank">{{ co.website | replace('https://', '') | replace('http://', '') }}</a>{% endif %}
</div>
{% endmacro %}

{% macro render_footer() %}
<div class="ol-footer">
  <div class="ol-footer-company">ORDER LIFT MOROCCO</div>
  <div class="ol-footer-address">Adresse : Tanja Balia lots méditerrané 475 rue plage Essalam Nr 15 Tanger, Maroc</div>
  <div class="ol-footer-meta">RC : 162443 - ICE : 003698266000073 - Email : <a href="mailto:info@orderlift.net">info@orderlift.net</a></div>
</div>
{% endmacro %}

{% macro render_info_grid() %}
<div class="ol-title-container">
  <div class="ol-title-text">{{ _("DEVIS DE VENTE") }}</div>
  <div class="ol-title-date">{{ _("Date") }}: {{ frappe.format_date(doc.transaction_date) }}</div>
</div>

<table class="ol-info-table">
  <tr>
    <td style="width: 50%; vertical-align: top; padding-right: 15px;">
      <div class="ol-info-title">{{ _("Destinataire") }}</div>
      <div class="ol-info-client-name">{{ doc.customer_name }}</div>
      <div class="ol-info-client-details">
        {%- if doc.address_display -%}
          {{ doc.address_display | replace('\n', '<br>') }}
        {%- endif -%}
      </div>
    </td>
    <td style="width: 50%; vertical-align: top; padding-left: 15px;">
      <div class="ol-info-title">{{ _("Informations") }}</div>
      <table class="ol-meta-table">
        {%- if doc.contact_mobile or doc.contact_phone -%}
        <tr>
          <td class="ol-meta-label">{{ _("Téléphone") }}</td>
          <td>: {{ doc.contact_mobile or doc.contact_phone }}</td>
        </tr>
        {%- endif -%}
        <tr>
          <td class="ol-meta-label">{{ _("Date") }}</td>
          <td>: {{ frappe.format_date(doc.transaction_date) }}</td>
        </tr>
        <tr>
          <td class="ol-meta-label">{{ _("N° Devis") }}</td>
          <td>: <b>{{ doc.name }}</b></td>
        </tr>
        {%- if doc.owner -%}
        <tr>
          <td class="ol-meta-label">{{ _("Commercial") }}</td>
          <td>: {{ frappe.db.get_value('User', doc.owner, 'full_name') or doc.owner }}</td>
        </tr>
        {%- endif -%}
      </table>
    </td>
  </tr>
</table>
{% endmacro %}

{% macro render_items_table(items_list, start_idx) %}
<table class="ol-items">
  <thead>
    <tr>
      <th class="tc" style="width: 40px;">No</th>
      <th class="tl" style="width: 100px;">{{ _("Code") }}</th>
      <th class="tc" style="width: 60px;">{{ _("Image") }}</th>
      <th class="tl">{{ _("Désignation") }}</th>
      <th class="tr" style="width: 110px;">{{ _("Prix Unit. HT") }}</th>
      <th class="tc" style="width: 50px;">{{ _("Qté") }}</th>
      <th class="tr" style="width: 110px;">{{ _("Montant HT") }}</th>
    </tr>
  </thead>
  <tbody>
    {%- for item in items_list %}
    {%- set item_image = frappe.db.get_value('Item', item.item_code, 'image') %}
    <tr>
      <td class="tc">{{ start_idx + loop.index }}</td>
      <td class="ol-item-code">{{ item.item_code }}</td>
      <td class="tc">
        {%- if item_image %}
          <img class="ol-item-img" src="{{ item_image }}" alt="{{ item.item_code }}">
        {%- else %}
          <div class="ol-item-img-placeholder">&#128247;</div>
        {%- endif %}
      </td>
      <td>
        <div class="ol-item-name">{{ item.item_name }}</div>
        {%- if item.description and item.description != item.item_name %}
          <div class="ol-item-desc">{{ item.description }}</div>
        {%- endif %}
      </td>
      <td class="tr">{{ format_currency_fr(item.rate, doc.currency) }}</td>
      <td class="tc" style="font-weight: 600;">{{ item.qty | int if item.qty == (item.qty | int) else item.qty }}</td>
      <td class="tr" style="font-weight: 700;">{{ format_currency_fr(item.amount, doc.currency) }}</td>
    </tr>
    {%- endfor %}
  </tbody>
</table>
{% endmacro %}

{% macro render_totals_and_signatures() %}
<div class="ol-totals-container">
  <table class="ol-totals-table">
    <tr>
      <td class="tr">{{ _("Sous-total HT") }} :</td>
      <td class="ol-totals-value">{{ format_currency_fr(doc.total, doc.currency) }}</td>
    </tr>
    {%- for tax in doc.taxes %}
    <tr>
      <td class="tr">{{ tax.description }} :</td>
      <td class="ol-totals-value">{{ format_currency_fr(tax.tax_amount, doc.currency) }}</td>
    </tr>
    {%- endfor %}
    {%- if doc.discount_amount %}
    <tr>
      <td class="tr">{{ _("Remise") }} :</td>
      <td class="ol-totals-value">- {{ format_currency_fr(doc.discount_amount, doc.currency) }}</td>
    </tr>
    {%- endif %}
    <tr class="ol-totals-grand-row">
      <td class="tr"><b>{{ _("TOTAL TTC") }}</b> ({{ doc.currency }}) :</td>
      <td class="ol-totals-value"><b>{{ format_currency_fr(doc.grand_total, doc.currency) }}</b></td>
    </tr>
  </table>
</div>

<div class="ol-payment-terms">
  Mode de paiement : 40% à la commande, 50 % à la livraison totale du matériel, 10% Mise en marche
</div>

{%- if doc.terms -%}
<div class="ol-terms-container">
  <div class="ol-terms-title">{{ _("Conditions Générales") }}</div>
  <div class="ol-terms-text">{{ doc.terms }}</div>
</div>
{%- endif -%}

<table class="ol-sig-table">
  <tr>
    <td style="width: 48%; vertical-align: top; border-top: 1px solid #d1d5db; padding-top: 10px;">
      <div class="ol-sig-title">{{ _("Vendeur (Signature et Cachet)") }}</div>
      <div class="ol-sig-placeholder">
        <img src="/files/gem_signature.png" alt="Signature Vendeur" style="max-height: 80px; object-fit: contain;">
      </div>
      <div class="ol-sig-details">
        <b>{{ doc.company }}</b>
      </div>
    </td>
    <td style="width: 4%;"></td>
    <td style="width: 48%; vertical-align: top; border-top: 1px solid #d1d5db; padding-top: 10px;">
      <div class="ol-sig-title">{{ _("Client (Signature et Cachet)") }}</div>
      <div class="ol-sig-placeholder"></div>
      <div class="ol-sig-details" style="font-style: italic; color: #9ca3af;">
        {{ _("Bon pour accord") }}
      </div>
    </td>
  </tr>
</table>
{% endmacro %}

{# ==================== PAGES RENDERING ==================== #}

<!-- --- PAGE 1: COVER PAGE --- -->
<div class="ol-page ol-cover-page">
  <div class="ol-cover-container">
    <div class="ol-cover-header">
      <div class="ol-cover-logo">
        {%- if company_logo -%}
          <img src="{{ company_logo }}" alt="{{ doc.company }}">
        {%- else -%}
          <span style="font-size: 20px; font-weight: 800; color: #111827;">{{ doc.company }}</span>
        {%- endif -%}
      </div>
      <div style="font-size: 10px; color: #6b7280;">
        info@orderlift.net
      </div>
    </div>

    <table class="ol-cover-body-table">
      <tr>
        <td style="width: 55%; vertical-align: middle; padding-right: 20px;">
          <div class="ol-cover-image-container">
            <img class="ol-cover-img" src="/files/orderlift_cover.png" alt="Orderlift Elevator Cover">
          </div>
        </td>
        <td style="width: 45%; vertical-align: middle; padding-left: 20px;">
          <div class="ol-cover-details">
            <div class="ol-cover-brand">ORDER LIFT MOROCCO</div>
            <div class="ol-cover-subtitle">{{ _("Ascenseurs & Équipements") }}</div>
            <div class="ol-cover-title">{{ _("PROPOSITION COMMERCIALE") }}</div>
            <div class="ol-cover-divider"></div>

            <div class="ol-cover-meta-item">
              <div class="ol-cover-meta-label">{{ _("Préparé pour") }}</div>
              <div class="ol-cover-meta-value">{{ doc.customer_name }}</div>
            </div>

            <div class="ol-cover-meta-item">
              <div class="ol-cover-meta-label">{{ _("N° Document") }}</div>
              <div class="ol-cover-meta-value">{{ doc.name }}</div>
            </div>

            <div class="ol-cover-meta-item">
              <div class="ol-cover-meta-label">{{ _("Date") }}</div>
              <div class="ol-cover-meta-value">{{ frappe.format_date(doc.transaction_date) }}</div>
            </div>
          </div>
        </td>
      </tr>
    </table>

    <div class="ol-cover-footer">
      <div class="ol-cover-partners">ORDERLIFT | GEM | SICOR</div>
      <div>
        www.orderlift.net
      </div>
    </div>
  </div>
</div>

<!-- --- CONTENT PAGES --- -->
{% if total_items <= 3 %}
  {# Page 2 contains everything #}
  <div class="ol-page">
    <div class="ol-page-inner">
      {{ render_header() }}
      {{ render_info_grid() }}
      {{ render_items_table(items, 0) }}
      {{ render_totals_and_signatures() }}
    </div>
    {{ render_footer() }}
  </div>
{% elif total_items == 4 %}
  {# Page 2 (items 1-2) #}
  <div class="ol-page">
    <div class="ol-page-inner">
      {{ render_header() }}
      {{ render_info_grid() }}
      {{ render_items_table(items[0:2], 0) }}
    </div>
    {{ render_footer() }}
  </div>
  {# Page 3 (items 3-4 and totals/signatures) #}
  <div class="ol-page">
    <div class="ol-page-inner">
      {{ render_header() }}
      <div style="height: 15px;"></div>
      {{ render_items_table(items[2:], 2) }}
      {{ render_totals_and_signatures() }}
    </div>
    {{ render_footer() }}
  </div>
{% elif total_items <= 6 %}
  {# Page 2 (items 1-3) #}
  <div class="ol-page">
    <div class="ol-page-inner">
      {{ render_header() }}
      {{ render_info_grid() }}
      {{ render_items_table(items[0:3], 0) }}
    </div>
    {{ render_footer() }}
  </div>
  {# Page 3 (items 4+ and totals/signatures) #}
  <div class="ol-page">
    <div class="ol-page-inner">
      {{ render_header() }}
      <div style="height: 15px;"></div>
      {{ render_items_table(items[3:], 3) }}
      {{ render_totals_and_signatures() }}
    </div>
    {{ render_footer() }}
  </div>
{% elif total_items <= 8 %}
  {# Page 2 (items 1-4) #}
  <div class="ol-page">
    <div class="ol-page-inner">
      {{ render_header() }}
      {{ render_info_grid() }}
      {{ render_items_table(items[0:4], 0) }}
    </div>
    {{ render_footer() }}
  </div>
  {# Page 3 (items 5+ and totals/signatures) #}
  <div class="ol-page">
    <div class="ol-page-inner">
      {{ render_header() }}
      <div style="height: 15px;"></div>
      {{ render_items_table(items[4:], 4) }}
      {{ render_totals_and_signatures() }}
    </div>
    {{ render_footer() }}
  </div>
{% elif total_items <= 10 %}
  {# Page 2 (items 1-4) #}
  <div class="ol-page">
    <div class="ol-page-inner">
      {{ render_header() }}
      {{ render_info_grid() }}
      {{ render_items_table(items[0:4], 0) }}
    </div>
    {{ render_footer() }}
  </div>
  {# Page 3 (items 5-7) #}
  <div class="ol-page">
    <div class="ol-page-inner">
      {{ render_header() }}
      <div style="height: 15px;"></div>
